import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums
  it.todo("should return 5 G premium for an empty item list (processing fee only)");
  it.todo("should return 105 G premium for a single sword (100 base + 5 fee)");
  it.todo("should return 65 G premium for a single amulet (60 base + 5 fee)");
  it.todo("should return 85 G premium for a single staff (80 base + 5 fee)");
  it.todo("should return 45 G premium for a single potion (40 base + 5 fee)");
  it.todo("should return 30 G premium for a single rune component (25 base + 5 fee)");
  it.todo("should return 165 G premium for a sword and an amulet (100 + 60 base + 5 fee)");

  // Quote: component block pricing
  it.todo("should return 55 G premium for 2 runes (2 * 25 = 50 base + 5 fee)");
  it.todo("should return 65 G premium for 3 runes (block of 3 alike = 60 base + 5 fee)");
  it.todo("should return 105 G premium for 4 runes (no block, 4 * 25 = 100 base + 5 fee)");
  it.todo("should return 80 G premium for 2 runes + 1 moonstone (no block, different types, 75 base + 5 fee)");
  it.todo("should return 125 G premium for 3 runes + 3 moonstones (two blocks, 60 + 60 = 120 base + 5 fee)");

  // Quote: item-specific modifiers
  it.todo("should add 50% curse surcharge to a cursed sword (100 + 50 = 150 base + 5 fee = 155 G)");
  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5 (100 + 30 = 130 base + 5 fee = 135 G)");
  it.todo("should apply both curse and high-enchantment surcharges on same item (100 + 50 + 30 = 180 base + 5 fee = 185 G)");
  it.todo("should apply item-specific modifiers only to the affected item in a multi-item policy");

  // Quote: policy-wide modifiers
  it.todo("should apply 10% first-insurance surcharge to every quote (100 + 10 = 110 base + 5 fee = 115 G)");
  it.todo("should apply 20% loyalty discount for customers with >= 2 years (100 - 20 = 80 base + 5 fee = 85 G)");
  it.todo("should apply 15% follow-up discount on second and subsequent quotes");

  // Quote: modifier stacking and rounding
  it.todo("should stack item-specific and policy-wide modifiers correctly (newcomer cursed sword = 165 G)");
  it.todo("should stack all modifiers for long-standing customer second contract (cursed enchanted sword = 160 G)");
  it.todo("should round premiums up in MHPCO's favor");

  // Claim: basic payout
  it.todo("should pay damage minus 100 G deductible for a standard item");
  it.todo("should reimburse at 50% for items with enchantment >= 8, then apply deductible");
  it.todo("should fully reimburse dragon-material items, then apply deductible");
  it.todo("should apply 50% rule when item has both enchantment >= 8 and dragon material");
  it.todo("should apply deductible per damaged item in a multi-item claim");

  // Claim: cap
  it.todo("should cap total payout at 2x insurance sum");
  it.todo("should track remaining cap across multiple claims on the same policy");

  // Claim: components
  it.todo("should apply standard reimbursement to components (no enchantment or material)");

  // Error handling
  it.todo("should reject unknown item types in a quote");
  it.todo("should reject claim damage for item not in the policy");
  it.todo("should reject negative damage amounts");
  it.todo("should reject more damages of a type than items insured");
});

