interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

type Step = QuoteStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;
    for (const item of step.items) {
      basePremium += BASE_PREMIUMS[item.type] ?? 0;
    }
    return { premium: basePremium + PROCESSING_FEE };
  });
  return { results };
}

