  // Claim: components
  it.todo("should apply standard reimbursement to components (no enchantment or material)");

  // Error handling
  it.todo("should reject unknown item types in a quote");
  it.todo("should reject claim damage for item not in the policy");
  it.todo("should reject negative damage amounts");
  it.todo("should reject more damages of a type than items insured");
});

