interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

type Step = QuoteStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.includes(item.type);

const calculateItemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type] ?? 0;
  let premium = base;
  if (item.cursed) {
    premium += base * CURSE_SURCHARGE_RATE;
  }
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return premium;
};

const calculateComponentPremium = (
  componentCounts: Record<string, number>,
): number => {
  let total = 0;
  for (const [type, count] of Object.entries(componentCounts)) {
    total +=
      count === BLOCK_SIZE
        ? BLOCK_PREMIUM
        : count * (BASE_PREMIUMS[type] ?? 0);
  }
  return total;
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  let quoteCount = 0;

  const results = scenario.steps.map((step) => {
    quoteCount++;

    const componentCounts: Record<string, number> = {};
    let totalBeforeFee = 0;

    for (const item of step.items) {
      if (isComponent(item)) {
        componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
      } else {
        totalBeforeFee += calculateItemPremium(item);
      }
    }

    totalBeforeFee += calculateComponentPremium(componentCounts);

    const policyBase = totalBeforeFee;

    // Policy-wide modifiers (all percentages of policyBase)
    let policyModifier = FIRST_INSURANCE_SURCHARGE_RATE;

    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
      policyModifier -= LOYALTY_DISCOUNT_RATE;
    }

    if (quoteCount > 1) {
      policyModifier -= FOLLOW_UP_DISCOUNT_RATE;
    }

    const finalPremium = policyBase * (1 + policyModifier) + PROCESSING_FEE;
    return { premium: Math.ceil(parseFloat(finalPremium.toFixed(10))) };
  });
  return { results };
}

