108	        ? BLOCK_PREMIUM
109	        : count * (BASE_PREMIUMS[type] ?? 0);
110	  }
111	  return total;
112	};
113	
114	const countByType = (items: { type: string }[]): Record<string, number> => {
115	  const counts: Record<string, number> = {};
116	  for (const item of items) {
117	    counts[item.type] = (counts[item.type] ?? 0) + 1;
118	  }
119	  return counts;
120	};
121	
122	const roundUpPremium = (value: number): number =>
123	  Math.ceil(parseFloat(value.toFixed(10)));
124	
125	const roundDownPayout = (value: number): number =>
126	  Math.floor(parseFloat(value.toFixed(10)));
127	
128	const processQuote = (
129	  step: QuoteStep,
130	  customer: { yearsWithMHPCO: number },
131	  quoteCount: number,
132	): { result: QuoteResult; policy: Omit<Policy, "remainingCap"> } => {
133	  const componentCounts: Record<string, number> = {};
134	  let itemTotal = 0;
135	  let policyBase = 0;
136	  let insuranceSum = 0;
137	
138	  for (const item of step.items) {
139	    if (!(item.type in BASE_PREMIUMS)) {
140	      throw new Error(`Unknown item type: ${item.type}`);
141	    }
142	    insuranceSum += INSURANCE_VALUES[item.type] ?? 0;
143	    if (isComponent(item)) {
144	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
145	    } else {
146	      itemTotal += calculateItemPremium(item);
147	      policyBase += BASE_PREMIUMS[item.type] ?? 0;
148	    }
149	  }
150	
151	  const componentPremium = calculateComponentPremium(componentCounts);
152	  itemTotal += componentPremium;
153	  policyBase += componentPremium;
154	
155	  let totalBeforeFee = itemTotal;
156	
157	  // Policy-wide modifiers (all percentages of policyBase)
158	  totalBeforeFee += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
159	
160	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
161	    totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
162	  }
163	
164	  if (quoteCount > 1) {
165	    totalBeforeFee -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
166	  }
167	
168	  const finalPremium = totalBeforeFee + PROCESSING_FEE;
169	
170	  return {
171	    result: { premium: roundUpPremium(finalPremium) },
172	    policy: { items: step.items, insuranceSum },
173	  };
174	};
175	
176	const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
177	  const damageCounts = countByType(damages.map((d) => ({ type: d.itemType })));
178	  const insuredCounts = countByType(policyItems);
179	
180	  for (const [type, count] of Object.entries(damageCounts)) {
181	    if (count > (insuredCounts[type] ?? 0)) {
182	      throw new Error(`More damages of type "${type}" than items insured`);
183	    }
184	  }
185	};
186	
187	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
188	  validateDamages(step.incident.damages, policy.items);
189	
190	  let totalPayout = 0;
191	  for (const damage of step.incident.damages) {
192	    const item = policy.items.find((i) => i.type === damage.itemType);
193	    if (!item) {
194	      throw new Error(`Damage for item type "${damage.itemType}" not in policy`);
195	    }
196	    if (damage.amount < 0) {
197	      throw new Error(`Negative damage amount: ${damage.amount}`);
198	    }
199	    let reimbursement = damage.amount;
200	
201	    if ((item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
202	      reimbursement = reimbursement * CLAIM_HIGH_ENCHANTMENT_RATE;
203	    }
204	
205	    const payout = Math.max(0, reimbursement - DEDUCTIBLE);
206	    totalPayout += payout;
207	  }
208	
209	  totalPayout = Math.min(totalPayout, policy.remainingCap);
210	  totalPayout = roundDownPayout(totalPayout);
211	  policy.remainingCap -= totalPayout;
212	
213	  return { payout: totalPayout, remainingCap: policy.remainingCap };
214	};
215	
216	export const processScenario = (scenario: Scenario): ScenarioOutput => {
217	  let quoteCount = 0;
218	  const policies: Map<number, Policy> = new Map();
219	
220	  const results = scenario.steps.map((step, stepIndex) => {
221	    if (step.op === "quote") {
222	      quoteCount++;
223	      const { result, policy } = processQuote(step, scenario.customer, quoteCount);
224	      policies.set(stepIndex, {
225	        ...policy,
226	        remainingCap: policy.insuranceSum * 2,
227	      });
228	      return result;
229	    } else {
230	      const policy = policies.get(step.policy)!;
231	      return processClaim(step, policy);
232	    }
233	  });
234	
235	  return { results };
236	};
